import React from 'react';
import { Pressable, StyleSheet, Text, View } from 'react-native';
import {
  canCancelOrder,
  canModifyOrder,
  formatCurrency,
  formatOrderDate,
  formatOrderNumber,
  ORDER_STATUS_META
} from '../data/orderModule';
import { OrderRecord } from '../services/firebaseService';
import { createShadow } from '../styles/shadows';

type OrderHistoryCardProps = {
  order: OrderRecord;
  onViewDetails: () => void;
  onReorder?: () => void;
  onTrack?: () => void;
  onCancel?: () => void;
  onModify?: () => void;
};

const OrderHistoryCard = ({
  order,
  onViewDetails,
  onReorder,
  onTrack,
  onCancel,
  onModify
}: OrderHistoryCardProps) => {
  const meta = ORDER_STATUS_META[order.status];

  return (
    <View style={styles.card}>
      <View style={styles.header}>
        <View>
          <Text style={styles.orderNumber}>{formatOrderNumber(order)}</Text>
          <Text style={styles.dateText}>{formatOrderDate(order.createdAt)}</Text>
        </View>
        <View style={[styles.statusPill, { backgroundColor: meta.background }]}>
          <Text style={[styles.statusText, { color: meta.text }]}>{meta.label}</Text>
        </View>
      </View>

      <View style={styles.infoRow}>
        <View style={styles.infoCell}>
          <Text style={styles.infoLabel}>Quantity</Text>
          <Text style={styles.infoValue}>{order.quantity} cans</Text>
        </View>
        <View style={styles.infoCell}>
          <Text style={styles.infoLabel}>Amount</Text>
          <Text style={styles.infoValue}>{formatCurrency(order.totalAmount)}</Text>
        </View>
      </View>

      <View style={styles.infoRow}>
        <View style={styles.infoCell}>
          <Text style={styles.infoLabel}>Payment</Text>
          <Text style={styles.infoValue}>{order.paymentMethod}</Text>
        </View>
        <View style={styles.infoCell}>
          <Text style={styles.infoLabel}>Status</Text>
          <Text style={styles.infoValue}>
            {order.paymentStatus === 'paid' ? 'Paid' : order.paymentStatus === 'partial' ? 'Part Paid' : 'Pending'}
          </Text>
        </View>
      </View>

      <View style={styles.actionRow}>
        <Pressable style={styles.secondaryButton} onPress={onViewDetails}>
          <Text style={styles.secondaryButtonText}>View Details</Text>
        </Pressable>
        {onTrack ? (
          <Pressable style={styles.secondaryButton} onPress={onTrack}>
            <Text style={styles.secondaryButtonText}>Track</Text>
          </Pressable>
        ) : null}
        {onReorder ? (
          <Pressable style={styles.primaryButton} onPress={onReorder}>
            <Text style={styles.primaryButtonText}>Reorder</Text>
          </Pressable>
        ) : null}
      </View>

      {canModifyOrder(order.status) && onModify ? (
        <Pressable style={styles.textButton} onPress={onModify}>
          <Text style={styles.textButtonText}>Modify quantity or delivery time</Text>
        </Pressable>
      ) : null}
      {canCancelOrder(order.status) && onCancel ? (
        <Pressable style={styles.cancelButton} onPress={onCancel}>
          <Text style={styles.cancelButtonText}>Cancel Order</Text>
        </Pressable>
      ) : null}
    </View>
  );
};

const styles = StyleSheet.create({
  card: {
    backgroundColor: 'white',
    borderRadius: 24,
    padding: 18,
    ...createShadow({ color: '#0C5E91', opacity: 0.05, radius: 14, elevation: 4 })
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'flex-start'
  },
  orderNumber: {
    color: '#10324A',
    fontSize: 17,
    fontWeight: '900'
  },
  dateText: {
    marginTop: 4,
    color: '#70879A',
    fontSize: 12
  },
  statusPill: {
    borderRadius: 999,
    paddingHorizontal: 12,
    paddingVertical: 7
  },
  statusText: {
    fontSize: 11,
    fontWeight: '800'
  },
  infoRow: {
    marginTop: 16,
    flexDirection: 'row',
    gap: 10
  },
  infoCell: {
    flex: 1,
    borderRadius: 18,
    backgroundColor: '#F6FBFF',
    padding: 12
  },
  infoLabel: {
    color: '#6F899C',
    fontSize: 11,
    fontWeight: '700',
    textTransform: 'uppercase'
  },
  infoValue: {
    marginTop: 6,
    color: '#10324A',
    fontSize: 14,
    fontWeight: '800'
  },
  actionRow: {
    marginTop: 16,
    flexDirection: 'row',
    gap: 10,
    flexWrap: 'wrap'
  },
  primaryButton: {
    flex: 1,
    minWidth: 100,
    backgroundColor: '#0D8DD8',
    borderRadius: 18,
    paddingVertical: 13,
    alignItems: 'center'
  },
  primaryButtonText: {
    color: 'white',
    fontSize: 14,
    fontWeight: '800'
  },
  secondaryButton: {
    flex: 1,
    minWidth: 100,
    backgroundColor: '#EAF7FF',
    borderRadius: 18,
    paddingVertical: 13,
    alignItems: 'center'
  },
  secondaryButtonText: {
    color: '#0E5D8F',
    fontSize: 14,
    fontWeight: '800'
  },
  textButton: {
    marginTop: 14
  },
  textButtonText: {
    color: '#0D63A8',
    fontSize: 13,
    fontWeight: '700'
  },
  cancelButton: {
    marginTop: 12,
    alignSelf: 'flex-start',
    backgroundColor: '#FFF1F1',
    borderRadius: 14,
    paddingHorizontal: 14,
    paddingVertical: 10
  },
  cancelButtonText: {
    color: '#B42318',
    fontSize: 13,
    fontWeight: '800'
  }
});

export default OrderHistoryCard;
